div.script:
                	function get_file_name() {
                		var file_content = document.getElementsByClassName("file-input");
                		var filesCount = file_content[0].files.length;
                		var textbox = document.getElementsByClassName("file-message");
                		var uploadBtn = document.getElementById("fileUploadBtn");
                		if (filesCount === 1) {
							var fileName = file_content[0].value.split('\\').pop();
							textbox[0].textContent = fileName;
							uploadBtn.classList.remove("d-none");
						} else {
							textbox.text(filesCount + ' files selected');
						}
					}
